import json
import boto3

def lambda_handler(event, context):
    dynamodb = boto3.resource('dynamodb')
    s3 = boto3.client('s3')
    sns = boto3.client('sns')
    sqs = boto3.client('sqs')
    
    # Example S3 operation
    s3_response = s3.list_buckets()
    
    # Example DynamoDB operation
    table = dynamodb.Table('example-table')
    dynamodb_response = table.scan()
    
    # Example SNS operation
    sns_response = sns.publish(
        TopicArn='arn:aws:sns:us-east-1:123456789012:example-topic',
        Message='Hello from Lambda!'
    )
    
    # Example SQS operation
    sqs_response = sqs.send_message(
        QueueUrl='https://sqs.us-east-1.amazonaws.com/123456789012/example-queue',
        MessageBody='Hello from Lambda!'
    )
    
    return {
        'statusCode': 200,
        'body': json.dumps({
            's3': s3_response,
            'dynamodb': dynamodb_response,
            'sns': sns_response,
            'sqs': sqs_response
        })
    }